$$::jsonb->'features'
  ) f
  where (f->'geometry'->>'type') = 'Polygon'
  and length(f->'properties'->>'name') > 3
  and not (f->'properties'->>'name' ilike '%SS.HH%')
  and not (f->'properties'->>'name' ilike '%Grifo%')
  and not (f->'properties'->>'name' ilike '%Caseta%')
)

update public.lotes l
set geom = ST_SetSRID(
        ST_GeomFromGeoJSON((d.f->'geometry')::text),
        4326
     )
from data d
where upper(trim(l.nombre_lote))
      = upper(trim(d.f->'properties'->>'name'));

update public.lotes
set
latitud = ST_Y(ST_Centroid(geom)),
longitud = ST_X(ST_Centroid(geom))
where geom is not null;